// :core:navigation/Routes.kt
sealed class Route(val route: String) {
    data object Home : Route("home")
    data class Profile(val userId: String) : Route("profile/{userId}") {
        fun createRoute(userId: String) = "profile/$userId"
    }
}

// :feature:home/HomeScreen.kt
@Composable
fun HomeScreen(onNavigateToProfile: (String) -> Unit) {
    Button(onClick = { onNavigateToProfile(userId) }) {
        Text("View Profile")
    }
}

// :app/NavHost setup
NavHost(navController, startDestination = Route.Home.route) {
    composable(Route.Home.route) {
        HomeScreen(onNavigateToProfile = { userId ->
            navController.navigate(Route.Profile.createRoute(userId))
        })
    }
    composable("profile/{userId}") { backStackEntry ->
        ProfileScreen(userId = backStackEntry.arguments?.getString("userId") ?: "")
    }
}

